"use client";

import { useState, useEffect } from "react";

const BuyerDashboard = () => {
  const [projects, setProjects] = useState([]);
  const [selectedProject, setSelectedProject] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const response = await fetch("http://localhost:8000/api/projects/");
      if (!response.ok) throw new Error("Failed to fetch projects");
      const data = await response.json();
      setProjects(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleProjectClick = (project) => {
    setSelectedProject(project);
  };

  const handleBookPlot = async (plotId) => {
    try {
      const token = localStorage.getItem("token");
      const response = await fetch(`http://localhost:8000/api/plots/${plotId}/status`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ status: "Booked" }),
      });
      if (!response.ok) throw new Error("Failed to book plot");
      alert("Plot booked successfully!");
      fetchProjects();
    } catch (err) {
      alert(err.message);
    }
  };

  const getFacingColor = (facing) => {
    const colors = {
      North: "bg-blue-500",
      South: "bg-orange-500",
      East: "bg-green-500",
      West: "bg-yellow-500",
    };
    return colors[facing] || "bg-gray-500";
  };

  const getStatusColor = (status) => {
    const colors = {
      Available: "text-green-600",
      Booked: "text-yellow-600",
      Sold: "text-red-600",
    };
    return colors[status] || "text-gray-600";
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-xl">Loading...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-xl text-red-600">Error: {error}</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-7xl mx-auto">
        <h1 className="text-3xl font-bold mb-8">Buyer Dashboard</h1>

        {!selectedProject ? (
          <div>
            <h2 className="text-xl font-semibold mb-4">Available Projects</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {projects.map((project) => (
                <div
                  key={project.id}
                  className="bg-white p-6 rounded-lg shadow-md cursor-pointer hover:shadow-lg transition"
                  onClick={() => handleProjectClick(project)}
                >
                  <h3 className="text-xl font-semibold mb-2">{project.name}</h3>
                  <p className="text-gray-600 mb-2">{project.location}</p>
                  <p className="text-gray-500 text-sm mb-4">{project.description}</p>
                  <div className="flex justify-between text-sm">
                    <span>Land: {project.land_length} x {project.land_width}</span>
                    <span>Plots: {project.num_plots}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div>
            <button
              onClick={() => setSelectedProject(null)}
              className="mb-4 px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700"
            >
              ← Back to Projects
            </button>
            <div className="bg-white p-6 rounded-lg shadow-md mb-6">
              <h2 className="text-2xl font-bold mb-2">{selectedProject.name}</h2>
              <p className="text-gray-600 mb-2">{selectedProject.location}</p>
              <p className="text-gray-500">{selectedProject.description}</p>
            </div>

            <h3 className="text-xl font-semibold mb-4">Available Plots</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {selectedProject.plots.map((plot) => (
                <div
                  key={plot.id}
                  className="bg-white p-4 rounded-lg shadow border-l-4 border-gray-300"
                >
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-lg font-semibold">Plot #{plot.plot_number}</span>
                    <span className={`px-2 py-1 rounded text-xs font-medium ${getFacingColor(plot.facing)} text-white`}>
                      {plot.facing}
                    </span>
                  </div>
                  <div className="text-sm text-gray-600 mb-2">
                    <p>Dimensions: {plot.length} x {plot.width}</p>
                    <p>Area: {plot.area} sq ft</p>
                    <p>Grid Position: Row {plot.row_index}, Col {plot.col_index}</p>
                    {plot.price && <p className="font-semibold">Price: ₹{plot.price.toLocaleString()}</p>}
                  </div>
                  <div className="mt-3">
                    <span className={`font-semibold ${getStatusColor(plot.status)}`}>
                      {plot.status}
                    </span>
                    {plot.status === "Available" && (
                      <button
                        onClick={() => handleBookPlot(plot.id)}
                        className="mt-2 w-full px-3 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
                      >
                        Book Now
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default BuyerDashboard;

"use client";

import { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const savedUser = localStorage.getItem("user");
    if (token && savedUser) {
      setUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  const login = (token, userData) => {
    localStorage.setItem("token", token);
    localStorage.setItem("user", JSON.stringify(userData));
    setUser(userData);
  };

  const logout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setUser(null);
  };

  const isAuthenticated = !!user;

  return (
    <AuthContext.Provider value={{ user, login, logout, isAuthenticated, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

"use client";

import { useState, useEffect } from "react";
import { filterPlots, getPlotFilters } from "../utils/plotFilters";

const FilterPanel = ({ plots, onFilterChange }) => {
  const [filters, setFilters] = useState({
    status: "all",
    minPrice: "",
    maxPrice: "",
    minArea: "",
    maxArea: "",
    minLength: "",
    maxLength: "",
    minWidth: "",
    maxWidth: "",
    facing: "all",
  });

  const [filterRanges, setFilterRanges] = useState(null);

  useEffect(() => {
    if (plots) {
      setFilterRanges(getPlotFilters(plots));
    }
  }, [plots]);

  useEffect(() => {
    const filtered = filterPlots(plots, {
      ...filters,
      minPrice: filters.minPrice ? Number(filters.minPrice) : null,
      maxPrice: filters.maxPrice ? Number(filters.maxPrice) : null,
      minArea: filters.minArea ? Number(filters.minArea) : null,
      maxArea: filters.maxArea ? Number(filters.maxArea) : null,
      minLength: filters.minLength ? Number(filters.minLength) : null,
      maxLength: filters.maxLength ? Number(filters.maxLength) : null,
      minWidth: filters.minWidth ? Number(filters.minWidth) : null,
      maxWidth: filters.maxWidth ? Number(filters.maxWidth) : null,
    });
    onFilterChange?.(filtered);
  }, [filters, plots]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
  };

  const clearFilters = () => {
    setFilters({
      status: "all",
      minPrice: "",
      maxPrice: "",
      minArea: "",
      maxArea: "",
      minLength: "",
      maxLength: "",
      minWidth: "",
      maxWidth: "",
      facing: "all",
    });
  };

  const hasActiveFilters = Object.values(filters).some(
    (v) => v !== "" && v !== "all"
  );

  return (
    <div className="bg-white p-4 rounded-lg shadow-md">
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-semibold text-gray-900">Filters</h3>
        {hasActiveFilters && (
          <button
            onClick={clearFilters}
            className="text-sm text-blue-600 hover:text-blue-700"
          >
            Clear All
          </button>
        )}
      </div>

      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Availability
          </label>
          <select
            value={filters.status}
            onChange={(e) => handleFilterChange("status", e.target.value)}
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="all">All</option>
            <option value="Available">Available</option>
            <option value="Booked">Booked</option>
            <option value="Sold">Sold</option>
          </select>
        </div>

        {filterRanges?.priceRange?.max > 0 && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Price Range (₹)
            </label>
            <div className="flex gap-2">
              <input
                type="number"
                placeholder={`Min ${filterRanges.priceRange.min}`}
                value={filters.minPrice}
                onChange={(e) => handleFilterChange("minPrice", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
              <input
                type="number"
                placeholder={`Max ${filterRanges.priceRange.max}`}
                value={filters.maxPrice}
                onChange={(e) => handleFilterChange("maxPrice", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>
          </div>
        )}

        {filterRanges?.areaRange?.max > 0 && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Area (sq ft)
            </label>
            <div className="flex gap-2">
              <input
                type="number"
                placeholder={`Min ${Math.floor(filterRanges.areaRange.min)}`}
                value={filters.minArea}
                onChange={(e) => handleFilterChange("minArea", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
              <input
                type="number"
                placeholder={`Max ${Math.floor(filterRanges.areaRange.max)}`}
                value={filters.maxArea}
                onChange={(e) => handleFilterChange("maxArea", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>
          </div>
        )}

        {filterRanges?.dimensionsRange?.maxLength > 0 && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Length (ft)
            </label>
            <div className="flex gap-2">
              <input
                type="number"
                placeholder={`Min ${filterRanges.dimensionsRange.minLength}`}
                value={filters.minLength}
                onChange={(e) => handleFilterChange("minLength", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
              <input
                type="number"
                placeholder={`Max ${filterRanges.dimensionsRange.maxLength}`}
                value={filters.maxLength}
                onChange={(e) => handleFilterChange("maxLength", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>
          </div>
        )}

        {filterRanges?.dimensionsRange?.maxWidth > 0 && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Width (ft)
            </label>
            <div className="flex gap-2">
              <input
                type="number"
                placeholder={`Min ${filterRanges.dimensionsRange.minWidth}`}
                value={filters.minWidth}
                onChange={(e) => handleFilterChange("minWidth", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
              <input
                type="number"
                placeholder={`Max ${filterRanges.dimensionsRange.maxWidth}`}
                value={filters.maxWidth}
                onChange={(e) => handleFilterChange("maxWidth", e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              />
            </div>
          </div>
        )}

        {filterRanges?.facingOptions?.length > 0 && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Facing
            </label>
            <select
              value={filters.facing}
              onChange={(e) => handleFilterChange("facing", e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="all">All</option>
              {filterRanges.facingOptions.map((facing) => (
                <option key={facing} value={facing}>
                  {facing}
                </option>
              ))}
            </select>
          </div>
        )}
      </div>
    </div>
  );
};

export default FilterPanel;

