"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/router";
import Link from "next/link";

const ManageProjectPage = () => {
  const router = useRouter();
  const { id } = router.query;
  const [project, setProject] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [plotUpdates, setPlotUpdates] = useState({});

  useEffect(() => {
    if (id) {
      fetchProject();
    }
  }, [id]);

  const fetchProject = async () => {
    try {
      const token = localStorage.getItem("token");
      const response = await fetch(`http://localhost:8000/api/projects/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!response.ok) throw new Error("Failed to fetch project details");
      const data = await response.json();
      setProject(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handlePlotChange = (plotId, field, value) => {
    setPlotUpdates((prev) => ({
      ...prev,
      [plotId]: {
        ...prev[plotId],
        [field]: value,
      },
    }));
  };

  const handleUpdatePlot = async (plotId) => {
    const updates = plotUpdates[plotId];
    if (!updates) return;

    try {
      const token = localStorage.getItem("token");
      // Update status
      if (updates.status) {
        await fetch(`http://localhost:8000/api/plots/${plotId}/status`, {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({ status: updates.status }),
        });
      }
      // You would typically have another endpoint for updating price
      // For now, we just refetch to see status changes
      fetchProject();
      setPlotUpdates((prev) => {
        const newUpdates = { ...prev };
        delete newUpdates[plotId];
        return newUpdates;
      });
    } catch (err) {
      setError(`Failed to update plot #${plotId}: ${err.message}`);
    }
  };

  if (loading) return <div className="p-8 text-center">Loading...</div>;
  if (error) return <div className="p-8 text-center text-red-600">Error: {error}</div>;
  if (!project) return <div className="p-8 text-center">Project not found.</div>;

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-7xl mx-auto">
        <div className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-3xl font-bold">Manage Project</h1>
            <p className="text-gray-600 mt-1">{project.name} - {project.location}</p>
          </div>
          <Link
            href="/admin/dashboard"
            className="px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700"
          >
            ← Back to Dashboard
          </Link>
        </div>

        <div className="bg-white p-8 rounded-lg shadow-md">
          <h2 className="text-2xl font-semibold mb-6">Plots Management</h2>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 py-3 text-left text-xs font-medium">Plot #</th>
                  <th className="px-4 py-3 text-left text-xs font-medium">Dimensions</th>
                  <th className="px-4 py-3 text-left text-xs font-medium">Area</th>
                  <th className="px-4 py-3 text-left text-xs font-medium">Facing</th>
                  <th className="px-4 py-3 text-left text-xs font-medium">Price (₹)</th>
                  <th className="px-4 py-3 text-left text-xs font-medium">Status</th>
                  <th className="px-4 py-3 text-right text-xs font-medium">Actions</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {project.plots.map((plot) => (
                  <tr key={plot.id}>
                    <td className="px-4 py-4 font-bold">{plot.plot_number}</td>
                    <td className="px-4 py-4 text-sm">{plot.length} x {plot.width} ft</td>
                    <td className="px-4 py-4 text-sm">{plot.area} sq ft</td>
                    <td className="px-4 py-4 text-sm">{plot.facing}</td>
                    <td className="px-4 py-4">
                      <input
                        type="number"
                        defaultValue={plot.price}
                        onChange={(e) => handlePlotChange(plot.id, "price", e.target.value)}
                        className="w-28 px-2 py-1 border rounded-md text-sm"
                      />
                    </td>
                    <td className="px-4 py-4">
                      <select
                        value={plotUpdates[plot.id]?.status || plot.status}
                        onChange={(e) => handlePlotChange(plot.id, "status", e.target.value)}
                        className="w-32 px-2 py-1 border rounded-md text-sm"
                      >
                        <option>Available</option>
                        <option>Booked</option>
                        <option>Sold</option>
                      </select>
                    </td>
                    <td className="px-4 py-4 text-right">
                      <button
                        onClick={() => handleUpdatePlot(plot.id)}
                        disabled={!plotUpdates[plot.id]}
                        className="px-3 py-1 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 disabled:bg-gray-400"
                      >
                        Update
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ManageProjectPage;

