"use client";

import EnquiryButton from "./EnquiryButton";

const PlotInfoPanel = ({ plot, onBook, onClose }) => {
  if (!plot) {
    return (
      <div className="bg-white p-6 rounded-lg shadow-lg text-center text-gray-500">
        <p>Select a plot from the grid to see its details.</p>
      </div>
    );
  }

  const getStatusColor = (status) => {
    const colors = {
      Available: "text-green-600",
      Booked: "text-yellow-600",
      Sold: "text-red-600",
    };
    return colors[status] || "text-gray-600";
  };

  const getFacingIcon = (facing) => {
    const icons = {
      North: "↑",
      South: "↓",
      East: "→",
      West: "←",
    };
    return icons[facing] || "?";
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-lg sticky top-24">
      <div className="flex justify-between items-start">
        <h3 className="text-2xl font-bold mb-4">Plot #{plot.plot_number}</h3>
        <button onClick={onClose} className="text-gray-500 hover:text-gray-800">&times;</button>
      </div>

      <div className="space-y-3 text-sm">
        <div className="flex justify-between border-b pb-2">
          <span className="text-gray-500">Status</span>
          <span className={`font-semibold ${getStatusColor(plot.status)}`}>
            {plot.status}
          </span>
        </div>
        <div className="flex justify-between border-b pb-2">
          <span className="text-gray-500">Dimensions</span>
          <span className="font-medium">{plot.length} ft x {plot.width} ft</span>
        </div>
        <div className="flex justify-between border-b pb-2">
          <span className="text-gray-500">Area</span>
          <span className="font-medium">{plot.area} sq ft</span>
        </div>
        <div className="flex justify-between border-b pb-2">
          <span className="text-gray-500">Facing</span>
          <span className="font-medium flex items-center gap-1">
            <span className="text-lg">{getFacingIcon(plot.facing)}</span>
            {plot.facing}
          </span>
        </div>
        <div className="flex justify-between">
          <span className="text-gray-500">Grid Position</span>
          <span className="font-medium">Row {plot.row_index + 1}, Col {plot.col_index + 1}</span>
        </div>
        {plot.price && (
          <div className="flex justify-between items-center border-t pt-3 mt-3">
            <span className="text-gray-600 font-medium">Price</span>
            <span className="text-xl font-bold text-green-700">₹{plot.price.toLocaleString()}</span>
          </div>
        )}
      </div>

      <div className="mt-6">
        {plot.status === "Available" && (
          <button
            onClick={() => onBook(plot)}
            className="w-full px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
          >
            Book Now
          </button>
        )}
        <EnquiryButton plot={plot} />
      </div>
    </div>
  );
};

export default PlotInfoPanel;

