"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/router";
import Link from "next/link";
import PlotInfoPanel from "../../components/PlotInfoPanel";
// Mock 3D viewer component
const PlotViewer = ({ plot }) => (
  <div className="w-full h-96 bg-gray-200 flex items-center justify-center rounded-lg shadow-inner">
    <p className="text-gray-500">3D-Viewer for plot #{plot?.plot_number}</p>
  </div>
);


const PlotDetailPage = () => {
  const router = useRouter();
  const { id } = router.query;
  const [plot, setPlot] = useState(null);
  const [project, setProject] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (id) {
      fetchPlotDetails();
    }
  }, [id]);

  const fetchPlotDetails = async () => {
    try {
      const token = localStorage.getItem("token");
      const response = await fetch(`http://localhost:8000/api/plots/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!response.ok) throw new Error("Failed to fetch plot details");
      const plotData = await response.json();
      setPlot(plotData);

      // Fetch project details to show breadcrumbs
      const projectResponse = await fetch(`http://localhost:8000/api/projects/${plotData.project_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!projectResponse.ok) throw new Error("Failed to fetch project details");
      const projectData = await projectResponse.json();
      setProject(projectData);

    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleBookPlot = async (plot) => {
    try {
      const token = localStorage.getItem("token");
      await fetch(`http://localhost:8000/api/plots/${plot.id}/status`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ status: "Booked" }),
      });
      fetchPlotDetails(); // Refetch to update UI
    } catch (err) {
      alert("Failed to book plot. Please try again.");
    }
  };

  if (loading) return <div className="p-8 text-center">Loading plot details...</div>;
  if (error) return <div className="p-8 text-center text-red-600">Error: {error}</div>;
  if (!plot) return <div className="p-8 text-center">Plot not found.</div>;

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-7xl mx-auto">
        <div className="mb-6">
          <Link href="/dashboard" className="text-blue-600 hover:underline">
            Dashboard
          </Link>
          <span className="mx-2">/</span>
          {project && (
            <>
              <Link href={`/projects/${project.id}`} className="text-blue-600 hover:underline">
                {project.name}
              </Link>
              <span className="mx-2">/</span>
            </>
          )}
          <span className="text-gray-600">Plot #{plot.plot_number}</span>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">
            <PlotViewer plot={plot} />
          </div>
          <div>
            <PlotInfoPanel
              plot={plot}
              onBook={handleBookPlot}
              onClose={() => router.back()}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default PlotDetailPage;

