"use client";

import { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';

const PlotViewer = ({ plot }) => {
    const mountRef = useRef(null);

    useEffect(() => {
        if (!plot) return;

        // Scene setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0xf0f0f0);

        // Camera setup
        const camera = new THREE.PerspectiveCamera(75, mountRef.current.clientWidth / mountRef.current.clientHeight, 0.1, 1000);
        camera.position.set(plot.width, plot.length, plot.width * 1.5);

        // Renderer setup
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(mountRef.current.clientWidth, mountRef.current.clientHeight);
        mountRef.current.appendChild(renderer.domElement);

        // OrbitControls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);
        const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
        directionalLight.position.set(10, 20, 5);
        scene.add(directionalLight);

        // Create plot geometry
        const geometry = new THREE.BoxGeometry(plot.width, 0.2, plot.length);
        const material = new THREE.MeshStandardMaterial({ color: 0x22c55e }); // green-600
        const cube = new THREE.Mesh(geometry, material);
        scene.add(cube);

        // Ground plane
        const planeGeometry = new THREE.PlaneGeometry(plot.width * 3, plot.length * 3);
        const planeMaterial = new THREE.MeshStandardMaterial({ color: 0xd4d4d4 }); // gray-300
        const plane = new THREE.Mesh(planeGeometry, planeMaterial);
        plane.rotation.x = -Math.PI / 2;
        plane.position.y = -0.1;
        scene.add(plane);

        // Animation loop
        const animate = () => {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        };
        animate();

        // Handle resize
        const handleResize = () => {
            camera.aspect = mountRef.current.clientWidth / mountRef.current.clientHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(mountRef.current.clientWidth, mountRef.current.clientHeight);
        };
        window.addEventListener('resize', handleResize);

        // Cleanup
        return () => {
            window.removeEventListener('resize', handleResize);
            if (mountRef.current) {
                mountRef.current.removeChild(renderer.domElement);
            }
        };
    }, [plot]);

    return (
        <div ref={mountRef} className="w-full h-96 rounded-lg shadow-inner overflow-hidden">
            {!plot && <div className="flex items-center justify-center h-full"><p>Loading 3D view...</p></div>}
        </div>
    );
};

export default PlotViewer;

