from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from typing import List
from .. import database, models, schemas, dependencies

router = APIRouter(prefix="/api/enquiries", tags=["enquiries"])

@router.post("/", response_model=schemas.Enquiry, status_code=201)
def create_enquiry(
    enquiry: schemas.EnquiryCreate, 
    db: Session = Depends(database.get_db)
):
    db_plot = db.query(models.Plot).filter(models.Plot.id == enquiry.plot_id).first()
    if not db_plot:
        raise HTTPException(status_code=404, detail="Plot not found")

    db_enquiry = models.Enquiry(**enquiry.dict())
    db.add(db_enquiry)
    db.commit()
    db.refresh(db_enquiry)
    return db_enquiry

@router.get("/", response_model=List[schemas.Enquiry])
def get_enquiries(
    db: Session = Depends(database.get_db),
    current_user: models.User = Depends(dependencies.admin_only)
):
    return db.query(models.Enquiry).all()

@router.get("/{enquiry_id}", response_model=schemas.Enquiry)
def get_enquiry(
    enquiry_id: int,
    db: Session = Depends(database.get_db),
    current_user: models.User = Depends(dependencies.admin_only)
):
    db_enquiry = db.query(models.Enquiry).filter(models.Enquiry.id == enquiry_id).first()
    if not db_enquiry:
        raise HTTPException(status_code=404, detail="Enquiry not found")
    return db_enquiry

@router.delete("/{enquiry_id}", status_code=204)
def delete_enquiry(
    enquiry_id: int,
    db: Session = Depends(database.get_db),
    current_user: models.User = Depends(dependencies.admin_only)
):
    db_enquiry = db.query(models.Enquiry).filter(models.Enquiry.id == enquiry_id).first()
    if not db_enquiry:
        raise HTTPException(status_code=404, detail="Enquiry not found")
    db.delete(db_enquiry)
    db.commit()
    return None

