"use client";

import { useState } from "react";

const EnquiryModal = ({ plot, onClose }) => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [message, setMessage] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    setError(null);

    try {
      // This is a mock API call, replace with your actual endpoint
      const response = await new Promise((resolve) =>
        setTimeout(() => {
          console.log("Submitting enquiry:", { name, email, message, plotId: plot.id });
          resolve({ ok: true });
        }, 1000)
      );

      if (!response.ok) {
        throw new Error("Failed to submit enquiry. Please try again later.");
      }

      setSuccess(true);
      setTimeout(() => {
        onClose();
      }, 2000); // Close modal after 2 seconds
    } catch (err) {
      setError(err.message);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-xl p-8 w-full max-w-md">
        {success ? (
          <div className="text-center">
            <h2 className="text-2xl font-bold text-green-600 mb-4">Enquiry Sent!</h2>
            <p>Thank you for your interest. We will get back to you shortly.</p>
          </div>
        ) : (
          <>
            <h2 className="text-2xl font-bold mb-4">Enquire about Plot #{plot.plot_number}</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label htmlFor="name" className="block text-sm font-medium">Name</label>
                <input
                  type="text"
                  id="name"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  required
                  className="w-full mt-1 p-2 border rounded-md"
                />
              </div>
              <div>
                <label htmlFor="email" className="block text-sm font-medium">Email</label>
                <input
                  type="email"
                  id="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  className="w-full mt-1 p-2 border rounded-md"
                />
              </div>
              <div>
                <label htmlFor="message" className="block text-sm font-medium">Message</label>
                <textarea
                  id="message"
                  rows="4"
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  required
                  className="w-full mt-1 p-2 border rounded-md"
                ></textarea>
              </div>
              {error && <div className="text-red-600 text-sm">{error}</div>}
              <div className="flex justify-end gap-4">
                <button
                  type="button"
                  onClick={onClose}
                  className="px-4 py-2 bg-gray-200 rounded-md"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={submitting}
                  className="px-4 py-2 bg-blue-600 text-white rounded-md disabled:bg-gray-400"
                >
                  {submitting ? "Submitting..." : "Submit Enquiry"}
                </button>
              </div>
            </form>
          </>
        )}
      </div>
    </div>
  );
};

const EnquiryButton = ({ plot }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);

  return (
    <>
      <button
        onClick={() => setIsModalOpen(true)}
        className="w-full mt-4 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors text-sm font-medium"
      >
        Submit Enquiry
      </button>
      {isModalOpen && <EnquiryModal plot={plot} onClose={() => setIsModalOpen(false)} />}
    </>
  );
};

export default EnquiryButton;

