"use client";

import { useState, useEffect } from "react";
import Link from "next/link";

const EnquiriesPage = () => {
  const [enquiries, setEnquiries] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchEnquiries();
  }, []);

  const fetchEnquiries = async () => {
    try {
      const token = localStorage.getItem("token");
      const response = await fetch("http://localhost:8000/api/enquiries", {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!response.ok) throw new Error("Failed to fetch enquiries");
      const data = await response.json();
      setEnquiries(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (enquiryId) => {
    if (window.confirm("Are you sure you want to delete this enquiry?")) {
      try {
        const token = localStorage.getItem("token");
        await fetch(`http://localhost:8000/api/enquiries/${enquiryId}`, {
          method: "DELETE",
          headers: { Authorization: `Bearer ${token}` },
        });
        fetchEnquiries();
      } catch (err) {
        alert("Failed to delete enquiry.");
      }
    }
  };

  if (loading) return <div className="p-8 text-center">Loading enquiries...</div>;
  if (error) return <div className="p-8 text-center text-red-600">Error: {error}</div>;

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-7xl mx-auto">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold">Enquiries</h1>
          <Link href="/admin/dashboard" className="px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700">
            ← Back to Dashboard
          </Link>
        </div>

        <div className="bg-white p-8 rounded-lg shadow-md">
          {enquiries.length === 0 ? (
            <p className="text-center text-gray-500">No enquiries yet.</p>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium">Plot ID</th>
                    <th className="px-6 py-3 text-left text-xs font-medium">Name</th>
                    <th className="px-6 py-3 text-left text-xs font-medium">Email</th>
                    <th className="px-6 py-3 text-left text-xs font-medium">Message</th>
                    <th className="px-6 py-3 text-right text-xs font-medium">Actions</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {enquiries.map((enquiry) => (
                    <tr key={enquiry.id}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <Link href={`/plot/${enquiry.plot_id}`} className="text-blue-600 hover:underline">
                          {enquiry.plot_id}
                        </Link>
                      </td>
                      <td className="px-6 py-4">{enquiry.name}</td>
                      <td className="px-6 py-4">{enquiry.email}</td>
                      <td className="px-6 py-4 max-w-sm truncate">{enquiry.message}</td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() => handleDelete(enquiry.id)}
                          className="text-red-600 hover:text-red-800"
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default EnquiriesPage;

