            const isSelected = selectedPlotId === plot.id;

            return (
              <div
                key={plot.id}
                onClick={() => plot.status !== "Sold" && onPlotClick && onPlotClick(plot)}
                className={`
                  aspect-square rounded flex flex-col items-center justify-center text-white text-xs font-medium
